    @Test
    @DisplayName("TC21: parse(File, charsetName, baseUri, parser) uses custom XML parser override branch")
    public void test_TC21() throws IOException {
        // Create temp XML file to satisfy parser non-null branch and file-loading branch
        File temp = File.createTempFile("tc21", ".xml");
        temp.deleteOnExit();
        String xmlContent = "<elem>XML</elem>";
        Files.write(temp.toPath(), xmlContent.getBytes(StandardCharsets.UTF_8));
        String charset = "UTF-8";
        String baseUri = "http://base/";
        Parser xmlParser = Parser.xmlParser();
        // When parsing with a non-null parser, should use parser.parseInput and preserve XML syntax and elements
        Document doc = Jsoup.parse(temp, charset, baseUri, xmlParser);
        assertEquals(xmlParser.getSettings().syntax(),
                     doc.outputSettings().syntax(),
                     "Expected document syntax to match XML parser syntax");
        assertTrue(doc.body().html().contains(xmlContent),
                   "Expected body to contain original XML elements");
    }

