    @Test
    @DisplayName("TC24: parse(URL, timeout) throws SocketTimeoutException when connection times out")
    public void test_TC24() throws Exception {
        URL url = new URL("http://example.com");
        int timeout = 10;
        Connection mockCon = mock(Connection.class);
        when(mockCon.timeout(timeout)).thenReturn(mockCon);
        when(mockCon.get()).thenThrow(new SocketTimeoutException("timeout"));
        try (MockedStatic<HttpConnection> httpConnMock = mockStatic(HttpConnection.class)) {
            httpConnMock.when(() -> HttpConnection.connect(url)).thenReturn((HttpConnection) mockCon);
            // Expect SocketTimeoutException from get()
            assertThrows(SocketTimeoutException.class,
                         () -> Jsoup.parse(url, timeout),
                         "Expected SocketTimeoutException when connection times out");
        }
    }

    @Test
    @DisplayName("TC25: parse(URL, timeout) throws HttpStatusException when HTTP status not OK")
    public void test_TC25() throws Exception {
        URL url = new URL("http://example.com");
        int timeout = 20;
        HttpStatusException httpEx = new HttpStatusException("err", 500, "");
        Connection mockCon = mock(Connection.class);
        when(mockCon.timeout(timeout)).thenReturn(mockCon);
        when(mockCon.get()).thenThrow(httpEx);
        try (MockedStatic<HttpConnection> httpConnMock = mockStatic(HttpConnection.class)) {
